import { Container, Box } from '@mui/material'
import React from 'react'

import Intro from "./sections/Intro";
import Home from "./sections/Home";
import About from "./sections/About";
import Project from "./sections/Project";
import Research from "./sections/Research";
import Navbar from "./Navbar";

import "./Header.css"


type Props = {}

function Header({}: Props) {
    const boxWidth = "80hw"
    return (
    <Container  maxWidth={false} disableGutters sx={{
        m:0, 
        p:0,    
    }}>        
        <Box id='main'>
            <Navbar/>
            <Box className="content" sx={{maxWidth:boxWidth, m:0, p:0}}>
                <Box className='introSection' id='introSection' role='region' sx={{height:"100vh", width:boxWidth, m:0, p:0}}>
                    <Intro/>
                </Box>
                <Box className='homeSection' id='homeSection' role='region' sx={{height:"100vh", width:boxWidth, m:0, p:0}}>
                    <Home/>
                </Box>
                <Box className='aboutSection' id='aboutSection' role='region' sx={{height:"100vh", width:boxWidth, m:0, p:0}}>
                    <About/>
                </Box>
                <Box className='projectSection' id='projectSection' role='region' sx={{height:"100vh", width:boxWidth, m:0, p:0}}>
                    <Project/>
                </Box>
                <Box className='researchSection' id='researchSection' role='region' sx={{height:"100vh", width:boxWidth, m:0, p:0}}>
                    <Research/>
                </Box>
                <Box className='contactsSection' id='contactsSection' role='region' sx={{height:"100vh", width:boxWidth, m:0, p:0}}>
                    <Box/>
                </Box>
            </Box>
        </Box>
    </Container>
    )
}

export default Header