import {Box, Button, Stack, Typography, useMediaQuery, useTheme, Avatar, Paper, IconButton, Chip, Container, Skeleton}  from '@mui/material'
import { Link } from 'react-scroll'
import React, { SyntheticEvent } from 'react'
import { Octokit } from '@octokit/rest'

import "./Project.css"
import left_arrow from "../../assets/left_arrow.svg";
import right_arrow from "../../assets/right_arrow.svg";


type LinkProp = {
    link: string;    
    label: string;
};


type ProjectItemProps = {
    image: string;
    title: string;
    content: string;
    link: LinkProp[];  
    mobile_interface: boolean;  
};


async function ParseGithubJSON() {

    function ParseJSON(response: any){
        const json: ProjectItemProps = {
            image: "https://avatars.githubusercontent.com/u/93180825?v=4",
            title: response['name'],
            content: response['description'],
            link: response['topics'].map((item: string) => ({link: "https://github.com/topics/" + item, label: item})),
            mobile_interface: false
        }
        return json
    }

    const APIUrl = 'GET /users/OmmarShaikh01/repos'
    const octokit = new Octokit({ auth: process.env.REACT_APP_PORTFOLIO_ACCESS_TOKEN });
    try {
        const response = await octokit.request(APIUrl);
        const response_json: Array<{}> = await response.data;
        return response_json.map((item: any) => ParseJSON(item))
    } catch(error) {
        return []
    }
}


function ProjectItem(Props: ProjectItemProps) {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));

    function CustomChip(link: LinkProp) {
        return(
        <a target="_blank" rel="noreferrer noopener" href={link.link}>
            <Chip
                clickable
                key={link.label}
                variant="outlined"
                label={link.label}
                sx={{textAlign:"justify", maxWidth:"96px", overflow: "hidden", textOverflow: "ellipsis"}}
            />
        </a>
        )
    }


    function Links() {
        const links = []
        if (Props.link.length > 4) {
            for(let i = 0; i < Props.link.length; i++){
                if (i === 4){
                    break
                } else {
                    links.push(<CustomChip {...Props.link[i]}/>)
                }
            }
        } else {
            for(let i = 0; i < Props.link.length; i++){
                links.push(<CustomChip {...Props.link[i]}/>)
            }
            for(let i = 0; i < (4 - Props.link.length); i++){
                links.push(<Skeleton variant="rectangular" width={80} height={32} />)
            }
        }

        if (Props.link.length === 0) {
            return (
            <Stack direction="row" spacing={2}>
                <Skeleton variant="rectangular" width={80} height={32} sx={{borderRadius: '4px'}}/>
                <Skeleton variant="rectangular" width={80} height={32} sx={{borderRadius: '4px'}}/>
                <Skeleton variant="rectangular" width={80} height={32} sx={{borderRadius: '4px'}}/>
                <Skeleton variant="rectangular" width={80} height={32} sx={{borderRadius: '4px'}}/>
            </Stack>
            )
        } else {
            return (
            <Stack direction="row" spacing={2}>
                {links.map(link => link)}
            </Stack>
            )
        }
    }

    if (!Props.mobile_interface) {
        return (
            <Box id="projectItemContent" sx={{
                height: "85vh",
                maxHeight: "85vh",
                width:"85vw",
                maxWidth:"85vw",
                m: 0,
                p: 0,
                pl: 2,
                display: 'flex',
                justifyContent: 'flex-start',
                alignItems: "center"
            }}>
                <Stack direction="row" spacing={4}>
                    <Paper elevation={6}>
                        <Box sx={{width:"40vw", maxWidth:"40vw", height:"80vh", maxHeight:"80vh", display:"flex"}}>
                            <img src={Props.image} alt="" />
                        </Box>
                    </Paper>
                    <Container disableGutters>
                        <Typography
                            sx={{fontWeight: "bold", color: "secondary.main", overflow: "hidden", textOverflow: "ellipsis", mb: 2}}
                            align={'left'} variant={'h3'}
                        >
                            {Props.title}
                        </Typography>
                        {Links()}
                        <Typography
                            sx={{fontWeight: "500", color: "text.primary", overflow: "hidden", textOverflow: "ellipsis", m: 0, mt: 2, mr: 2}}
                            align={'left'} variant={'body1'} paragraph={true}
                        >
                            {Props.content}
                        </Typography>
                    </Container>
                </Stack>
            </Box>
        )
    } else {
        return (
            <Box id="projectItemContent" sx={{
                height: "80vh",
                maxHeight: "80vh",
                width:"90vw",
                maxWidth:"90vw",
                m: 0,
                p: 2, 
                pb: 2,           
                display: 'flex',
                justifyContent: 'center',
                alignItems: "flex-start"
            }}>
                <Stack direction="column" spacing={2} sx={{alignItems: 'center', justifyContent: 'center'}}>
                    <Paper elevation={6}>
                        <Box sx={{width:"80vw", maxWidth:"80vw", height:"38vh", maxHeight:"38vh"}}>
                            <img src={Props.image} alt="" style={{width:"80vw", maxWidth:"80vw", height:"38vh", maxHeight:"38vh", transform: 'scale(1, 1)'}}/>
                        </Box>
                    </Paper>
                    <Container disableGutters>
                        <Typography
                            sx={{fontWeight: "bold", color: "secondary.main", overflow: "hidden", textOverflow: "ellipsis", mb: 2}}
                            align={'left'} variant={'h4'}
                        >
                            {Props.title}
                        </Typography>
                        {Links()}
                        <Typography
                            sx={{fontWeight: "500", color: "text.primary", overflow: "hidden", textOverflow: "ellipsis", m: 0, mt: 2, mr: 2}}
                            align={'left'} variant={'body2'} paragraph={true}
                        >
                            {Props.content}
                        </Typography>
                    </Container>
                </Stack>
            </Box>
        )
    }
}


