import {Box, Button, Stack, Typography, useMediaQuery, useTheme, Avatar, Paper}  from '@mui/material'
import { Link } from 'react-scroll'
import React from 'react'
import "./About.css"


type SkillItemProps = {
    Source: string,
    Href: string
    avatarSX: {
        border: number;
        borderColor: string;
        width: string;
        height: string;
        margin: string;
        padding: string;
        borderRadius: string;
    }
}

function SkillItem(Prop: SkillItemProps) {    
    return(
        <a target="_blank" rel="noreferrer noopener" href={Prop.Href}>
            <Avatar sx={Prop.avatarSX} variant="square"
                    src={Prop.Source}
                    alt=""/>
        </a>
    )
}


