function Skills() {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));    

    return (
        <Box id="skills" sx={{                              
            display: 'flex',         
            justifyContent: 'center', 
            alignItems: "flex-start",
            m: 0,
            p: 0            
        }}>
            <Box>
                <Typography align={isMobile ? ('center'):('left')} 
                    variant={isMobile ? ('h4'):('h2')}
                    sx={{fontWeight: "bold", color: "text.primary", m:1, ml:2}}
                >
                    Skills
                </Typography>    
                {isMobile ? (
                    <SkillsItemStack_IsMobile />
                ):(
                    <SkillsItemStack/>
                )}
            </Box>
        </Box>
    )
}


function AboutMe() {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));
    
    return (
        <Box id="aboutMe" sx={{                  
            display: 'flex',         
            justifyContent: 'center', 
            alignItems: "flex-start",
            m: 0,
            p: 0
        }}>
            <div>
                <Typography 
                    sx={{fontWeight: "bold", color: "text.primary", m:1, ml:2}} 
                    align={isMobile ? ('center'):('left')} variant={isMobile ? ('h4'):('h2')}
                >
                    About Me
                </Typography>
                <Typography 
                    sx={isMobile ? ({color: "text.primary"}):({color: "text.primary", width: "40vw",  maxWidth: "40vw"})} 
                    paragraph={true} align="left" variant={isMobile ? ('body2'):('h6')}
                >
                    I'm <mark>Ommar Shaikh</mark> a <mark>Full stack developer</mark> living in india. My 2 years of
                    experience has given me a strong foundation On building complex solutions. I am graduating from Mumbai
                    University with a Bachlors in <mark>Computer science</mark>. I have Creative experience in
                    making <mark>Android, Web and Desktop Apps</mark>. Mostly my contributions are in <mark>open source And
                    research projects</mark>. I am passionate about coding and solving problems through code, and I am
                    excited to work alongside other amazing programmers and learn so much more !
                </Typography>
            </div>
        </Box>
    )
}

export default function About() {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));
    
    return (
        <Box id="aboutContent" sx={{ 
            height: "100vh", 
            maxHeight: "100vh", 
            width:"98vw", 
            maxWidth:"98vw", 
            m: 0,
            p: 0,
            pt: "64px", 
            display: 'flex', 
            justifyContent: 'center', 
            alignItems: "center"
        }}>
            <Stack spacing={isMobile? 1: 20} 
                direction={isMobile? "column": "row"} 
                sx={isMobile? ({m: 0}):({m: 6})}
            > 
                <AboutMe/>
                <Skills/>
            </Stack>
        </Box>
    )
}