import { AppBar, Avatar, Box, Button, Container, IconButton, List, ListItem, ListItemAvatar, ListItemText, Menu, MenuItem, Paper, Slide, Stack, Toolbar, Typography, useMediaQuery, useScrollTrigger, useTheme } from '@mui/material'
import React from 'react'
import { Link } from 'react-scroll'

import user from "../assets/filled/user.svg"
import menu_dots_h from "../assets/filled/more-horiz.svg"
import menu_dots_v from "../assets/filled/more-vert.svg"
import "./Navbar.css"


function NavbarUserInfo() {
    return(
        <List sx={{p: 0, pr: '8px', m: 0}}>
            <ListItem sx={{p: 0, m: 0, alignItems: 'flex-start'}}>
                <ListItemAvatar sx={{ height: '64px', padding: "4px 4px"}}>
                    <Avatar src={user} alt="O" sx={{ border: 2, borderColor: 'secondary.main', width: '56px', height: '56px', p: "2px", m: 0}}/>
                </ListItemAvatar>
                <ListItemText
                    primary = {
                        <Link spy={true} smooth={true} duration={400} to="homeSection" >
                            <Typography variant="body1" sx={{pl:'4px', fontWeight: "900", color: 'secondary.main' }}>Ommar Shaikh</Typography>
                        </Link>
                    }
                    secondary={
                        <Link spy={true} smooth={true} duration={400} to="aboutSection" >
                            <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary' }}>Full Stack Developer</Typography>
                        </Link>
                    }
                />
            </ListItem>
        </List>
    )
}


function NavbarItemStack() {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));
    const [menuExpanded, setmenuExpanded] = React.useState(false);
    const [menuAnchorEl, setmenuAnchorEl] = React.useState<null | HTMLElement>(null);
    
    const expandMenu = (event: React.MouseEvent<HTMLButtonElement>) => {
        if(menuExpanded)  {
            setmenuAnchorEl(null)
            setmenuExpanded(false)
        } else {
            setmenuAnchorEl(event.currentTarget)
            setmenuExpanded(true)
        }
    }

    return(
    <div>
        {isMobile ? (
            <div>
                <IconButton color={'secondary'} sx={{p: 2, m: 0, width: '64px', height: '64px'}} onClick={expandMenu}>
                    {menuExpanded ? (
                        <Avatar src={menu_dots_v} alt="O" sx={{width: '32px', height: '32px', p: 0, m: 0}}/>
                    ):(
                        <Avatar src={menu_dots_h} alt="O" sx={{width: '32px', height: '32px', p: 0, m: 0}}/>
                    )}                                        
                </IconButton>
                <Paper elevation={6}>
                    <Menu open={menuExpanded} onClose={expandMenu} anchorEl={menuAnchorEl}>
                        <MenuItem>
                            <Link spy={true} smooth={true} duration={400} to="homeSection" >
                                <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary' }}>Home</Typography>
                            </Link>
                        </MenuItem>
                        <MenuItem>
                            <Link spy={true} smooth={true} duration={400} to="aboutSection" >
                                <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary' }}>About</Typography>
                            </Link>
                        </MenuItem>
                        <MenuItem>
                            <Link spy={true} smooth={true} duration={400} to="projectSection" >
                                <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary' }}>Projects</Typography>
                            </Link>
                        </MenuItem>
                        <MenuItem>
                            <Link spy={true} smooth={true} duration={400} to="researchSection" >
                                <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary' }}>Research</Typography>
                            </Link>
                        </MenuItem>
                        <MenuItem>
                            <Link spy={true} smooth={true} duration={400} to="contactsSection" >
                                <Typography variant="caption" sx={{pl:'4px', fontWeight: "400", color: 'text.primary' }}>Contacts</Typography>
                            </Link>
                        </MenuItem>
                    </Menu>
                </Paper>
            </div>
        ) : (
            <Stack direction="row" spacing={2} sx={{height: '64px', alignItems: 'center'}}>
                <Link spy={true} smooth={true} duration={400} to="homeSection" >
                    <Button size="large" color="secondary">Home</Button>
                </Link>
                <Link spy={true} smooth={true} duration={400} to="aboutSection" >
                    <Button size="large" color="secondary">About</Button>
                </Link>
                <Link spy={true} smooth={true} duration={400} to="projectSection" >
                    <Button size="large" color="secondary">Projects</Button>
                </Link>
                <Link spy={true} smooth={true} duration={400} to="researchSection" >
                    <Button size="large" color="secondary">Research</Button>
                </Link>
                <Link spy={true} smooth={true} duration={400} to="contactsSection" >
                    <Button size="large" color="secondary">Contacts</Button>
                </Link>
            </Stack>
        )}
    </div>
    )
}


type Props = {}

function Navbar({}: Props) {
    const theme = useTheme();
    const [nav, setnav] = React.useState(false)
    const changeBackground = () => {
        if(window.scrollY >= 80)  {
            setnav(true)
        } else {
            setnav(false)
        }
    }
    window.addEventListener('scroll', changeBackground)

    return (
        <Slide appear={false} in={nav} direction="down">
            <Paper>
                <AppBar>
                    <Toolbar disableGutters sx={{bgcolor: 'transparent', padding: 0, margin: 0}}>                    
                        <Container maxWidth={false} disableGutters sx={{
                            m:0,
                            p:0,                                    
                            height: '64px',
                            maxHeight: '64px',
                            width: "100vw", 
                            maxWidth: "100vw",
                            display: 'flex',
                            justifyContent: 'space-between',
                            
                        }}>
                            <NavbarUserInfo/>
                            <NavbarItemStack/>
                        </Container>                    
                    </Toolbar>
                </AppBar>
            </Paper>
        </Slide>
    )
}

export default Navbar