import {Box, Button, Stack, Typography, useMediaQuery, useTheme}  from '@mui/material'
import { Link } from 'react-scroll'
import React from 'react'
import "./Home.css"


type Props = {}

export default function Home({}: Props) {
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down("md"));
    
    return (
        <Box id="homeContent" sx={{ 
            height: "100vh", 
            maxHeight: "100vh", 
            width:"98vw", 
            maxWidth:"98vw", 
            display: 'flex', 
            pt: 8, 
            justifyContent: 'center', 
            alignItems: "center"
        }}>
            <Stack spacing={2} sx={{ width:"70vw", maxWidth:"70vw"}}>
                <Typography sx={{fontWeight: "400", color: "text.primary"}} align="center" variant={isMobile ? ('h4'):('h2')}>Hi, I'am</Typography>
                <Typography sx={{fontWeight: "bold", color: "secondary.main"}} align="center" variant={isMobile ? ('h4'):('h2')}>Ommar Shaikh</Typography>
                <Typography sx={{fontWeight: "400", color: "text.primary"}} align="center" variant={isMobile ? ('h4'):('h2')}>a Full Stack Developer</Typography>
                <Typography sx={{fontWeight: "900", color: "primary.main"}} paragraph={true} align="center" variant="body1">I Specialize in a variety of technologies like Firebase, SQL, Django, Qt, etc using Python, Web, And Android. Being a Developer is One Of my life goals, with a talent is this field i want to keep learning new things and strengthen my previous knowledge</Typography>
                <Stack sx={{ width:"100%", maxWidth:"100%", pt: "16px", justifyContent: "center"}} direction="row" spacing={4}>
                    <Link className="cv-btn" id="title" spy={true} smooth={true} duration={400} to="contactsSection" >
                        <Button variant="outlined" size="large" color="secondary">Contacts</Button>
                    </Link>
                    <Link className="cv-btn" id="title" spy={true} smooth={true} duration={400} to="aboutSection" >
                        <Button variant="outlined" size="large" color="secondary">Resume</Button>
                    </Link>
                </Stack>
            </Stack>
        </Box>
    )
}